tests:
def test_starts_closed():
    cb = CircuitBreaker(failure_threshold=3, recovery_timeout=1.0)
    assert cb.stats().state == CircuitState.CLOSED

def test_failure_counted():
    cb = CircuitBreaker(failure_threshold=3, recovery_timeout=1.0)
    def bad():
        raise RuntimeError('fail')
    try:
        cb.call(bad)
    except RuntimeError:
        pass
    assert cb.stats().failures == 1

def test_opens_after_threshold():
    cb = CircuitBreaker(failure_threshold=2, recovery_timeout=1.0)
    def bad():
        raise RuntimeError('fail')
    for _ in range(2):
        try:
            cb.call(bad)
        except RuntimeError:
            pass
    assert cb.stats().state == CircuitState.OPEN

def test_open_blocks_calls():
    cb = CircuitBreaker(failure_threshold=1, recovery_timeout=1.0)
    try:
        cb.call(lambda: (_ for _ in ()).throw(RuntimeError()))
    except RuntimeError:
        pass
    try:
        cb.call(lambda: 1)
        assert False, 'should have raised BreakerOpenError'
    except BreakerOpenError:
        pass

def test_half_open_failure_reopens():
    import time
    cb = CircuitBreaker(failure_threshold=1, recovery_timeout=0.05)
    try:
        cb.call(lambda: (_ for _ in ()).throw(RuntimeError()))
    except RuntimeError:
        pass
    time.sleep(0.1)
    try:
        cb.call(lambda: (_ for _ in ()).throw(RuntimeError()))
    except RuntimeError:
        pass
    assert cb.stats().state == CircuitState.OPEN

def test_consecutive_failures_required():
    cb = CircuitBreaker(failure_threshold=2, recovery_timeout=1.0)
    def bad():
        raise RuntimeError()
    try:
        cb.call(bad)
    except RuntimeError:
        pass
    cb.call(lambda: 'ok')
    try:
        cb.call(bad)
    except RuntimeError:
        pass
    assert cb.stats().state == CircuitState.CLOSED
